import json, re

with open('config.json') as f:
    config = json.load(f)
with open('schema.json') as f:
    schema = json.load(f)

errors = []

# Check required fields
for field in schema.get('required', []):
    if field not in config:
        errors.append(f'Missing required field: {field}')

# Check name
if 'name' in config:
    if not isinstance(config['name'], str) or len(config['name']) < 1:
        errors.append('name must be a non-empty string')
    if config['name'] != 'example-widget':
        errors.append(f'name must equal example-widget, got: {config[\"name\"]}')

# Check version
if 'version' in config:
    pattern = r'^[0-9]+\.[0-9]+\.[0-9]+$'
    if not re.match(pattern, config['version']):
        errors.append(f'version does not match semver pattern: {config[\"version\"]}')

if errors:
    print('VALIDATION ERRORS:', errors)
else:
    print('config.json: valid ✓')
    print('name:', config['name'])
    print('version:', config['version'])
"
